import{_ as a,o as e,c as i,ae as l}from"./chunks/framework.EHGTsUvI.js";const m=JSON.parse('{"title":"Prompt 核心框架：角色、上下文、任务与格式","description":"","frontmatter":{},"headers":[],"relativePath":"ai-tutorial/prompt-basics.md","filePath":"ai-tutorial/prompt-basics.md"}'),r={name:"ai-tutorial/prompt-basics.md"};function s(p,t,o,n,d,c){return e(),i("div",null,[...t[0]||(t[0]=[l(`<h1 id="prompt-核心框架-角色、上下文、任务与格式" tabindex="-1">Prompt 核心框架：角色、上下文、任务与格式 <a class="header-anchor" href="#prompt-核心框架-角色、上下文、任务与格式" aria-label="Permalink to &quot;Prompt 核心框架：角色、上下文、任务与格式&quot;">​</a></h1><blockquote><p>Prompt 被讲得最玄乎的时候，往往也是它最容易被误解的时候。很多人一听“提示词工程”，脑子里先冒出来的是措辞技巧，像在练一种面向模型的话术。 可真实工程里，Prompt 真正值钱的部分通常不在“说得漂亮”，而在“边界划得清楚、上下文喂得合适、输出结构接得住”。</p></blockquote><div class="info custom-block"><p class="custom-block-title">这篇文章重点</p><ul><li>一个实用 Prompt 应该至少包含哪些部分</li><li>为什么 system / user / context 的分层很重要</li><li>如何用格式约束和失败兜底提高稳定性</li></ul></div><h2 id="_1-一个好-prompt-最少要回答四个问题" tabindex="-1">1. 一个好 Prompt 最少要回答四个问题 <a class="header-anchor" href="#_1-一个好-prompt-最少要回答四个问题" aria-label="Permalink to &quot;1. 一个好 Prompt 最少要回答四个问题&quot;">​</a></h2><p>你可以把基础 Prompt 组织成四部分：</p><table tabindex="0"><thead><tr><th>维度</th><th>要回答的问题</th></tr></thead><tbody><tr><td>角色（Role）</td><td>你希望模型站在什么职责位置上工作</td></tr><tr><td>上下文（Context）</td><td>它需要知道哪些背景信息</td></tr><tr><td>任务（Task）</td><td>它具体要做什么</td></tr><tr><td>格式（Format）</td><td>结果应该长什么样</td></tr></tbody></table><p>很多不稳定输出，往往是因为这四部分缺了一两块。</p><h2 id="_2-system-提示词的价值-是定义边界" tabindex="-1">2. system 提示词的价值，是定义边界 <a class="header-anchor" href="#_2-system-提示词的价值-是定义边界" aria-label="Permalink to &quot;2. system 提示词的价值，是定义边界&quot;">​</a></h2><p>system 提示词最适合放：</p><ul><li>角色定义</li><li>全局约束</li><li>安全边界</li><li>输出原则</li></ul><p>例如：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你是企业内部知识助手。</span></span>
<span class="line"><span>如果证据不足，请明确说明不知道。</span></span>
<span class="line"><span>不得编造来源。</span></span>
<span class="line"><span>优先输出结构化要点。</span></span></code></pre></div><p>这比在每轮用户输入里反复强调更稳定。</p><h2 id="_3-上下文要尽量相关-而不是尽量多" tabindex="-1">3. 上下文要尽量相关，而不是尽量多 <a class="header-anchor" href="#_3-上下文要尽量相关-而不是尽量多" aria-label="Permalink to &quot;3. 上下文要尽量相关，而不是尽量多&quot;">​</a></h2><p>模型并不会因为你塞了更多背景就自动更懂。相反，过长、过杂的上下文常常会降低输出质量。</p><p>更好的原则是：</p><ul><li>只提供决策所需信息</li><li>保持信息来源清晰</li><li>对长资料先做压缩或检索</li></ul><h2 id="_4-格式约束是工程稳定性的核心" tabindex="-1">4. 格式约束是工程稳定性的核心 <a class="header-anchor" href="#_4-格式约束是工程稳定性的核心" aria-label="Permalink to &quot;4. 格式约束是工程稳定性的核心&quot;">​</a></h2><p>如果输出需要被系统继续消费，就应该尽量明确格式，例如：</p><ul><li>JSON</li><li>Markdown 列表</li><li>固定字段模板</li></ul><p>相比“请输出详细分析”，更稳的写法往往是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>请按以下 JSON 字段返回：</span></span>
<span class="line"><span>summary、risk_level、evidence、next_action</span></span></code></pre></div><h2 id="_5-失败兜底也要写进-prompt" tabindex="-1">5. 失败兜底也要写进 Prompt <a class="header-anchor" href="#_5-失败兜底也要写进-prompt" aria-label="Permalink to &quot;5. 失败兜底也要写进 Prompt&quot;">​</a></h2><p>很多系统默认模型“一定能答”。更稳妥的方式是提前告诉它：</p><ul><li>证据不足怎么办</li><li>字段缺失怎么办</li><li>多种情况冲突怎么办</li></ul><p>这类兜底规则对稳定性帮助很大。</p><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to &quot;小结&quot;">​</a></h2><p>Prompt 的基础功，不在辞藻，而在结构。把角色、上下文、任务和格式组织清楚，再辅以适度的失败兜底，往往比盲目“润色提示词”更有效。</p><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://platform.openai.com/docs/guides/prompt-engineering" target="_blank" rel="noreferrer">OpenAI: Prompt engineering</a></li><li><a href="https://docs.anthropic.com/en/docs/prompt-engineering" target="_blank" rel="noreferrer">Anthropic: Prompt engineering overview</a></li><li>延伸阅读：<a href="./advanced-prompting.html">进阶 Prompt 策略</a></li></ul>`,30)])])}const u=a(r,[["render",s]]);export{m as __pageData,u as default};
